/**
 * Strategic Heatmap Layer
 *
 * deck.gl WebGL layer for the 12-year strategic PM density view.
 * Renders a heatmap grid where:
 * - Rows = trains
 * - Columns = years
 * - Cell color = PM density (intensity)
 *
 * Used at zoom levels 0-8 (STRATEGIC and TACTICAL_WIDE).
 *
 * @see specs/006-user-interface.md Section 6.3.2
 */

import { ScatterplotLayer, TextLayer } from '@deck.gl/layers';
import DeckGL from '@deck.gl/react';
import { OrthographicView } from '@deck.gl/core';

import type { StrategicCanvasData, HeatmapCell } from './types';

// =============================================================================
// Constants
// =============================================================================

const CELL_WIDTH = 80;
const CELL_HEIGHT = 30;
const CELL_PADDING = 4;
const LABEL_WIDTH = 100;
const HEADER_HEIGHT = 40;

/** PM density color scale (light to dark blue) */
const PM_DENSITY_COLORS: [number, number, number, number][] = [
  [240, 249, 255, 255], // 0 PMs - very light blue
  [186, 230, 253, 255], // 1 PM - light blue
  [125, 211, 252, 255], // 2 PMs
  [56, 189, 248, 255],  // 3 PMs
  [14, 165, 233, 255],  // 4 PMs
  [2, 132, 199, 255],   // 5 PMs
  [3, 105, 161, 255],   // 6 PMs
  [7, 89, 133, 255],    // 7+ PMs - dark blue
];

/** Fleet colors */
const FLEET_COLORS: Record<string, [number, number, number, number]> = {
  KS: [14, 165, 233, 255],   // Sky-500
  ALSTOM: [139, 92, 246, 255], // Violet-500
  DEFAULT: [100, 116, 139, 255], // Slate-500
};

// =============================================================================
// Helper Functions
// =============================================================================

/**
 * Transform API data into heatmap cells with positions
 */
function transformToHeatmapCells(
  data: StrategicCanvasData,
  fromYear: number,
  toYear: number
): HeatmapCell[] {
  const cells: HeatmapCell[] = [];
  const { trains, heatmapData } = data;
  const maxPmCount = heatmapData.maxPmCount || 1;

  trains.forEach((train, trainIndex) => {
    for (let year = fromYear; year <= toYear; year++) {
      const yearIndex = year - fromYear;
      const yearData = train.years.find((y) => y.year === year);

      const pmCount = yearData?.pmCount ?? 0;
      const totalHours = yearData?.totalHours ?? 0;
      const completedCount = yearData?.completedCount ?? 0;
      const lockedCount = yearData?.lockedCount ?? 0;

      const intensity = Math.min(pmCount / maxPmCount, 1);

      const x = LABEL_WIDTH + yearIndex * (CELL_WIDTH + CELL_PADDING);
      const y = HEADER_HEIGHT + trainIndex * (CELL_HEIGHT + CELL_PADDING);

      cells.push({
        trainId: train.trainId,
        trainNumber: train.trainNumber,
        trainIndex,
        year,
        yearIndex,
        pmCount,
        totalHours,
        completedCount,
        lockedCount,
        intensity,
        position: [x + CELL_WIDTH / 2, y + CELL_HEIGHT / 2],
      });
    }
  });

  return cells;
}

/**
 * Get color for PM density
 */
function getDensityColor(intensity: number): [number, number, number, number] {
  const index = Math.min(
    Math.floor(intensity * (PM_DENSITY_COLORS.length - 1)),
    PM_DENSITY_COLORS.length - 1
  );
  return PM_DENSITY_COLORS[index];
}

// =============================================================================
// Component Props
// =============================================================================

export interface StrategicHeatmapProps {
  data: StrategicCanvasData | null;
  fromYear: number;
  toYear: number;
  width: number | string;
  height: number | string;
  onCellHover?: (cell: HeatmapCell | null) => void;
  onCellClick?: (cell: HeatmapCell) => void;
  onYearClick?: (year: number) => void;
}

// =============================================================================
// Component
// =============================================================================

/**
 * Strategic Heatmap View
 *
 * Renders a PM density heatmap using deck.gl WebGL layers.
 * Optimized for 60fps rendering of 100+ trains × 10 years.
 */
export function StrategicHeatmapLayer({
  data,
  fromYear,
  toYear,
  width,
  height,
  onCellHover,
  onCellClick,
  onYearClick,
}: StrategicHeatmapProps) {
  if (!data || data.trains.length === 0) {
    return (
      <div
        style={{
          width,
          height,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: 'var(--pt-text-muted)',
        }}
      >
        No strategic data available
      </div>
    );
  }

  const cells = transformToHeatmapCells(data, fromYear, toYear);
  const yearCount = toYear - fromYear + 1;
  const trainCount = data.trains.length;

  const canvasWidth = LABEL_WIDTH + yearCount * (CELL_WIDTH + CELL_PADDING) + 40;
  const canvasHeight = HEADER_HEIGHT + trainCount * (CELL_HEIGHT + CELL_PADDING) + 40;

  const trainLabels = data.trains.map((train, index) => ({
    text: train.trainNumber,
    fleetCode: train.fleetCode,
    position: [LABEL_WIDTH / 2, HEADER_HEIGHT + index * (CELL_HEIGHT + CELL_PADDING) + CELL_HEIGHT / 2] as [number, number],
  }));

  const yearLabels: Array<{ text: string; year: number; position: [number, number] }> = [];
  for (let year = fromYear; year <= toYear; year++) {
    const yearIndex = year - fromYear;
    yearLabels.push({
      text: String(year),
      year,
      position: [
        LABEL_WIDTH + yearIndex * (CELL_WIDTH + CELL_PADDING) + CELL_WIDTH / 2,
        HEADER_HEIGHT / 2,
      ] as [number, number],
    });
  }

  const layers = [
    new ScatterplotLayer<HeatmapCell>({
      id: 'heatmap-cells',
      data: cells,
      pickable: true,
      opacity: 1,
      stroked: true,
      filled: true,
      radiusScale: 1,
      radiusMinPixels: 1,
      radiusMaxPixels: 100,
      lineWidthMinPixels: 1,
      getPosition: (d) => [...d.position, 0] as [number, number, number],
      getRadius: Math.min(CELL_WIDTH, CELL_HEIGHT) / 2 - 2,
      getFillColor: (d) => getDensityColor(d.intensity),
      getLineColor: [200, 200, 200, 255],
      getLineWidth: 1,
      onHover: (info) => {
        if (onCellHover) {
          onCellHover(info.object ?? null);
        }
      },
      onClick: (info) => {
        if (info.object && onCellClick) {
          onCellClick(info.object);
        }
      },
      updateTriggers: {
        getFillColor: [data],
      },
    }),

    new TextLayer<{ text: string; fleetCode: string; position: [number, number] }>({
      id: 'train-labels',
      data: trainLabels,
      pickable: false,
      getPosition: (d) => [...d.position, 0] as [number, number, number],
      getText: (d) => d.text,
      getSize: 12,
      getAngle: 0,
      getTextAnchor: 'middle',
      getAlignmentBaseline: 'center',
      getColor: (d) => FLEET_COLORS[d.fleetCode] || FLEET_COLORS.DEFAULT,
      fontFamily: 'Inter, system-ui, sans-serif',
      fontWeight: 600,
    }),

    new TextLayer<{ text: string; year: number; position: [number, number] }>({
      id: 'year-labels',
      data: yearLabels,
      pickable: true,
      getPosition: (d) => [...d.position, 0] as [number, number, number],
      getText: (d) => d.text,
      getSize: 14,
      getAngle: 0,
      getTextAnchor: 'middle',
      getAlignmentBaseline: 'center',
      getColor: [30, 41, 59, 255],
      fontFamily: 'Inter, system-ui, sans-serif',
      fontWeight: 700,
      onClick: (info) => {
        if (info.object && onYearClick) {
          onYearClick(info.object.year);
        }
      },
    }),
  ];

  const initialViewState = {
    target: [canvasWidth / 2, canvasHeight / 2, 0] as [number, number, number],
    zoom: 0,
    minZoom: -2,
    maxZoom: 4,
  };

  return (
    <DeckGL
      width={width}
      height={height}
      views={new OrthographicView({ id: 'main' })}
      initialViewState={initialViewState}
      controller={{
        scrollZoom: true,
        dragPan: true,
        dragRotate: false,
        doubleClickZoom: true,
        touchZoom: true,
        touchRotate: false,
        keyboard: true,
      }}
      layers={layers}
      getCursor={({ isHovering }) => (isHovering ? 'pointer' : 'grab')}
      style={{ position: 'absolute', top: '0', left: '0' }}
    />
  );
}

// =============================================================================
// Tooltip Component
// =============================================================================

export interface HeatmapTooltipProps {
  cell: HeatmapCell | null;
  x: number;
  y: number;
}

/**
 * Tooltip for heatmap cell hover
 */
export function HeatmapTooltip({ cell, x, y }: HeatmapTooltipProps) {
  if (!cell) return null;

  return (
    <div
      style={{
        position: 'absolute',
        left: x + 10,
        top: y + 10,
        backgroundColor: 'white',
        border: '1px solid #e2e8f0',
        borderRadius: '6px',
        padding: '8px 12px',
        boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
        pointerEvents: 'none',
        zIndex: 100,
        fontSize: '12px',
        lineHeight: 1.5,
      }}
    >
      <div style={{ fontWeight: 600, marginBottom: '4px' }}>
        Train {cell.trainNumber} - {cell.year}
      </div>
      <div style={{ color: '#64748b' }}>
        <div>PM Count: <strong>{cell.pmCount}</strong></div>
        <div>Total Hours: <strong>{cell.totalHours.toFixed(1)}h</strong></div>
        {cell.completedCount > 0 && (
          <div>Completed: <strong>{cell.completedCount}</strong></div>
        )}
        {cell.lockedCount > 0 && (
          <div>Locked: <strong>{cell.lockedCount}</strong></div>
        )}
      </div>
    </div>
  );
}

export default StrategicHeatmapLayer;

