   331→      400
   332→    );
   333→  }
   334→
   335→  const numWeeks = weeksParam ? parseInt(weeksParam, 10) : 12;
   336→  if (isNaN(numWeeks) || numWeeks < 1 || numWeeks > 52) {
   337→    return c.json(
   338→      error(ErrorCodes.VALIDATION_ERROR, 'Weeks must be between 1 and 52', requestId),
   339→      400
   340→    );
   341→  }
   342→
   343→  const latestRunResult = await db
   344→    .select({ projectionRunId: manhourProjections.projectionRunId })
   345→    .from(manhourProjections)
   346→    .orderBy(desc(manhourProjections.createdAt))
   347→    .limit(1);
   348→
   349→  if (latestRunResult.length === 0) {
   350→    return c.json(
   351→      success(
   352→        { weeks: [] },
   353→        { timing: { durationMs: getRequestDuration(c) } }
   354→      )
   355→    );
   356→  }
   357→
   358→  const latestRunId = latestRunResult[0].projectionRunId;
   359→
   360→  const conditions = [
   361→    eq(manhourProjections.projectionRunId, latestRunId),
   362→    eq(manhourProjections.granularity, 'WEEKLY'),
   363→  ];
   364→
   365→  if (depotIdParam) {
   366→    conditions.push(eq(manhourProjections.depotId, depotIdParam));
   367→  }
   368→
   369→  const projections = await db
   370→    .select({
   371→      projectionId: manhourProjections.id,
   372→      depotId: manhourProjections.depotId,
   373→      depotCode: depots.code,
   374→      periodStart: manhourProjections.periodStart,
   375→      periodEnd: manhourProjections.periodEnd,
   376→      requiredHours: manhourProjections.requiredTotalHours,
   377→      availableHours: manhourProjections.availableTotalHours,
   378→    })
   379→    .from(manhourProjections)
   380→    .innerJoin(depots, eq(manhourProjections.depotId, depots.id))
   381→    .where(and(...conditions))
   382→    .orderBy(manhourProjections.periodStart, depots.code)
   383→    .limit(numWeeks * 10);
   384→
   385→  const adjustmentsResult = await db
   386→    .select({
   387→      projectionId: manhourAdjustments.projectionId,
   388→      adjustmentType: manhourAdjustments.adjustmentType,
   389→      hoursAdjusted: manhourAdjustments.hoursAdjusted,
   390→      status: manhourAdjustments.status,
   391→    })
   392→    .from(manhourAdjustments)
   393→    .where(
   394→      and(
   395→        inArray(
   396→          manhourAdjustments.projectionId,
   397→          projections.map((p) => p.projectionId)
   398→        ),
   399→        eq(manhourAdjustments.status, 'PROPOSED')
   400→      )
   401→    );
   402→
   403→  const adjustmentsByProjection = new Map<string, typeof adjustmentsResult>();
   404→  for (const adj of adjustmentsResult) {
   405→    if (!adjustmentsByProjection.has(adj.projectionId)) {
   406→      adjustmentsByProjection.set(adj.projectionId, []);
   407→    }
   408→    adjustmentsByProjection.get(adj.projectionId)!.push(adj);
   409→  }
   410→
   411→  const weekMap = new Map<string, {
   412→    weekStart: string;
   413→    depots: Array<{
   414→      depotId: string;
   415→      depotCode: string;
   416→      requiredHours: number;
   417→      availableHours: number;
   418→      utilizationPct: number;
   419→      status: 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
