   441→    }
   442→
   443→    const adjustments = (adjustmentsByProjection.get(proj.projectionId) || []).map((a) => ({
   444→      type: a.adjustmentType,
   445→      hours: parseFloat(a.hoursAdjusted),
   446→      status: a.status ?? 'PROPOSED',
   447→    }));
   448→
   449→    if (!weekMap.has(weekStart)) {
